{
    TripletMarginLossCustomTilingData tiling;
    const gert::Shape* anchorShape = context->GetInputShape(0);
    const uint32_t batchSize = anchorShape->GetOriginShape().GetDim(0);
    const uint32_t featureDim = anchorShape->GetOriginShape().GetDim(1);

